```csharp
using System;
using System.Collections.Generic;

public class NQueens
{
    private int n;
    private int[] queens; // queens[row] = column
    private List<int[]> solutions = new List<int[]>();

    public NQueens(int n)
    {
        this.n = n;
        this.queens = new int[n];
    }

    public List<int[]> SolveNQueens()
    {
        SolveNQueensUtil(0);
        return solutions;
    }

    private void SolveNQueensUtil(int row)
    {
        if (row == n)
        {
            // Found a solution.  Create a copy to store.
            int[] solution = new int[n];
            Array.Copy(queens, solution, n);
            solutions.Add(solution);
            return;
        }

        for (int col = 0; col < n; col++)
        {
            if (IsSafe(row, col))
            {
                queens[row] = col;
                SolveNQueensUtil(row + 1);
            }
        }
    }

    private bool IsSafe(int row, int col)
    {
        for (int i = 0; i < row; i++)
        {
            // Check if the current column is occupied by a previously placed queen
            if (queens[i] == col)
            {
                return false;
            }

            // Check diagonals.  If difference in rows == difference in columns, then they are on the same diagonal
            if (Math.Abs(queens[i] - col) == Math.Abs(i - row))
            {
                return false;
            }
        }

        return true;
    }

    public void PrintSolutions()
    {
        foreach (int[] solution in solutions)
        {
            PrintBoard(solution);
            Console.WriteLine();
        }
    }

    private void PrintBoard(int[] solution)
    {
        for (int i = 0; i < n; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (solution[i] == j)
                {
                    Console.Write("Q ");
                }
                else
                {
                    Console.Write(". ");
                }
            }
            Console.WriteLine();
        }
    }

    public static void Main(string[] args)
    {
        int n = 8; // Change this to the desired board size
        NQueens nQueens = new NQueens(n);
        List<int[]> solutions = nQueens.SolveNQueens();

        Console.WriteLine($"Found {solutions.Count} solutions for the {n}-Queens problem:");
        nQueens.PrintSolutions();
    }
}
```

