N 퀸 문제로 알려진 퍼즐은 N개의 체스 퀸을 N×N 체스판에 서로 위협할 수 없도록 배치하는 문제입니다. 이는 유효한 해법은 두 퀸이 보드의 동일한 행, 열 또는 대각선에 위치하지 않도록 보장해야 함을 의미합니다.

```csharp
// N 퀸 배치를 위한 C# 코드
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // 체스판의 최대 크기
    static int MAX = 10;

    // 퀸 배치를 저장할 배열
    static int[] arr = new int[MAX];

    // 찾은 해법의 수를 세는 변수
    static int no;

    // 해법을 찾기 위한 재귀 함수
    static void nQueens(int k, int n)
    {
        // 현재 행에서 퀸에 대한 모든 가능한 위치를 시도합니다.
        for (int i = 1; i <= n; i++)
        {
            // 현재 위치에 퀸을 배치할 수 있는지 확인합니다.
            if (canPlace(k, i))
            {
                // 현재 위치에 퀸을 배치합니다.
                arr[k] = i;

                // 모든 퀸이 배치되면 해법을 표시합니다.
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // 나머지 퀸을 배치하기 위해 재귀적으로 시도합니다.
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // 퀸을 현재 위치에 배치할 수 있는지 확인하는 도우미 함수
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // 퀸이 이미 동일한 열 또는 대각선에 배치되어 있는지 확인합니다.
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // 해법을 표시하는 함수
    static void display(int n)
    {
        breakLine();
        Console.Write("배치 번호. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // 빈 셀에는 '_'를, 퀸이 있는 셀에는 'Q'를 인쇄합니다.
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // 문제를 초기화하고 재귀 함수를 호출하는 드라이버 코드
    public static void Main(String[] args)
    {
        int n = 4; // 체스판의 크기
        nQueens(1, n);
    }
}
```

