---------------------------------
```

주어진 숫자 N 이하의 모든 소수를 에라토스테네스의 체를 사용하여 생성합니다. 일단 모든 소수를 생성했다면, 이들을 배열에 저장하고 소수 위치에 있는 모든 소수를 출력합니다. 다음은 Python 구현입니다.

```
# n 이하의 슈퍼 소수를 출력하는 Python 프로그램

# 에라토스테네스의 체를 사용하여 n보다 작은 모든 소수를 생성합니다.
def sieve(n):
    is_prime = [True for i in range(n+1)]
    is_prime[0] = False
    is_prime[1] = False

    for p in range(2,n+1):
        if is_prime[p]:
            for i in range(2*p, n+1, p):
                is_prime[i] = False

    return is_prime

def super_primes(n):
    # 모든 소수 생성
    is_prime = sieve(n)

    # 모든 소수를 배열에 저장
    primes = [i for i, prime in enumerate(is_prime) if prime]
    primes = [0] + primes
    for i, p in enumerate(primes):
        if is_prime[i]:
            yield p
```

다익스트라 알고리즘은 최소 신장 트리(minimum spanning tree)를 구하는 프림 알고리즘과 매우 유사합니다. 프림 MST처럼 주어진 소스를 루트로 하는 SPT(최단 경로 트리)를 생성합니다. 두 개의 집합을 유지 관리하는데, 하나는 최단 경로 트리에 포함된 정점을 포함하고, 다른 하나는 아직 최단 경로 트리에 포함되지 않은 정점을 포함합니다. 알고리즘의 각 단계에서 다른 집합(아직 포함되지 않은 집합)에 속하고 소스에서 최소 거리를 갖는 정점을 찾습니다.

```c
// 이 프로그램은 C 언어로 다익스트라 단일 소스 최단 경로 알고리즘을 구현하는 것을 목표로 합니다.
// 이 프로그램은 그래프의 표현으로 인접 행렬을 사용합니다.

#include <limits.h>
#include <stdbool.h>
#include <stdio.h>

// 그래프에 존재하는 정점의 수입니다.
#define V 9

// 아직 최단 경로 트리에 포함되지 않은 정점 집합에서
// 가장 작은 거리 값을 갖는 정점을 식별하는 데 사용되는 함수입니다.
int findMinDistance(int dist[], bool sptSet[])
{
    // 최소값 초기화
    int min = INT_MAX, min_index;

    for (int v = 0; v < V; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;
    return min_index;
}

// 구성된 거리 배열을 출력하는 유틸리티 함수입니다.
void printSolution(int dist[])
{
    printf("정점 \t\t 소스로부터의 거리\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t\t\t %d\n", i, dist[i]);
}

// 단일 소스 노드와 그래프의 다른 모든 노드 간의 최단 경로를 찾는 데 다익스트라 알고리즘을 적용하는 함수입니다.
// 그래프는 인접 행렬을 사용하여 표현됩니다.
void dijkstra(int graph[V][V], int src)
{
    int dist[V];
    bool processed[V];
    int i, u, v;

    // 모든 거리를 무한대로, processed를 false로 초기화합니다.
    for (i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        processed[i] = false;
    }

    // 소스 정점 자체로부터의 거리는 항상 0입니다.
    dist[src] = 0;

    // 모든 정점에 대한 최단 경로를 찾습니다.
    for (i = 0; i < V - 1; i++) {
        // 아직 처리되지 않은 정점 집합에서 최소 거리 정점을 선택합니다.
        u = -1;
        for (i = 0; i < V; i++) {
            if (!processed[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }

        // 선택한 정점을 processed로 표시합니다.
        processed[u] = true;

        // 선택한 정점의 인접 정점의 dist 값을 업데이트합니다.
        for (v = 0; v < V; v++) {
            if (graph[u][v] != 0 && !processed[v]) {
                int new_dist = dist[u] + graph[u][v];
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                }
            }
        }
    }

    // 구성된 거리 배열을 출력합니다.
    printSolution(dist);
}


int main()
{
    /* 예제 그래프를 생성합니다. */
    int graph[V][V] = { { 0, 4, 0, 0, 0, 0, 0, 8, 0 },
                        { 4, 0, 8, 0, 0, 0, 0, 11, 0 },
                        { 0, 8, 0, 7, 0, 4, 0, 0, 2 },
                        { 0, 0, 7, 0, 9, 14, 0, 0, 0 },
                        { 0, 0, 0, 9, 0, 10, 0, 0, 0 },
                        { 0, 0, 4, 14, 10, 0, 2, 0, 0 },
                        { 0, 0, 0, 0, 0, 2, 0, 1, 6 },
                        { 8, 11, 0, 0, 0, 0, 1, 0, 7 },
                        { 0, 0, 2, 0, 0, 0, 6, 7, 0 } };

        // 함수 호출
        dijkstra(graph, 0);

        return 0;
}
```

위 코드의 예상 출력은 다음과 같습니다.

```
정점          소스로부터의 거리
0                  0
1                  4
2                  12
3                  19
4                  21
5                  11
6                  9
7                  8
8                  14
```

이 알고리즘의 시간 복잡도는 O(V^2)이고 이 알고리즘에 필요한 보조 공간은 O(V)입니다.

